// // This latch holds the data input when the enable is high and resets to 1 when the reset is high.
module d_latch (
  input D,
  input EN,
  input RST,
  output Q
);

  reg Q_reg;

  always @ (posedge EN) begin
    if (RST) begin
      Q_reg <= 1'b0;
    end else begin
      Q_reg <= D;
    end
  end

  assign Q = Q_reg;

endmodule
